    if (X[i] == first) {
        len2++; len1++;
    } else if (X[i] == second) {
        len2++;
        len1 = (P);
        // Swapping first and second to keep track of the most recent two elements
        int temp = first;
        first = second;
        second = temp;
    } else {
        len2 = (Q);
        len1 = 1;
